import React from 'react';
import { Outlet } from 'react-router-dom';

// Importamos los componentes clave del layout
// Asumimos que existen en el mismo directorio (components/)
import Header from './Header'; 
import Footer from './Footer';
// Importamos los componentes de feedback visual que deben ser globales
import Notification from './Notification';
import ToastNotification from './ToastNotification'; 
import LoadingOverlay from './LoadingOverlay';

const Layout = () => {
  return (
    // Estructura flex para asegurar que el footer siempre esté en la parte inferior (min-h-screen)
    <div className="flex flex-col min-h-screen">
      
      {/* Las notificaciones globales y el spinner de carga van fuera del <main> */}
      <LoadingOverlay />
      <Notification />
      <ToastNotification />
      
      {/* 1. Header (Pegajoso y Oscuro) */}
      <Header />
      
      {/* 2. Main Content: Ocupa el espacio restante y renderiza la página actual */}
      {/* flex-grow es CRÍTICO para empujar el Footer hacia abajo */}
      <main className="flex-grow">
        <Outlet /> 
      </main>
      
      {/* 3. Footer (Oscuro) */}
      <Footer />
      
    </div>
  );
};

export default Layout;
